document.addEventListener("DOMContentLoaded",function(){"use strict";const t=document.querySelectorAll(".about-feature-card");if(t.length){const e=new IntersectionObserver(t=>{t.forEach(t=>{if(t.isIntersecting){const n=t.target,s=parseInt(n.dataset.cardIndex||0,10);setTimeout(()=>{n.classList.add("is-visible")},s*120),e.unobserve(n)}})},{threshold:.12,rootMargin:"0px 0px -60px 0px"});t.forEach(t=>e.observe(t))}const n=document.querySelector(".timeline-wrapper");if(!n)return;const e=document.querySelectorAll(".timeline-row"),s=document.querySelector(".timeline-line");e.forEach(e=>{e.style.animationPlayState="paused"});const o=new IntersectionObserver(t=>{t.forEach(t=>{t.isIntersecting&&(s&&s.classList.add("animate"),e.forEach((e,t)=>{setTimeout(()=>{e.classList.add("is-visible"),e.style.animationPlayState="running"},t*150)}),o.unobserve(t.target))})},{threshold:.1,rootMargin:"0px 0px -50px 0px"}),i=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&e.target.classList.add("is-visible")})},{threshold:.2,rootMargin:"0px 0px -100px 0px"});o.observe(n),e.forEach(e=>{i.observe(e)}),e.forEach(e=>{const t=e.querySelector(".timeline-marker"),n=e.querySelector(".timeline-content");t&&n&&(e.addEventListener("mouseenter",()=>{t.classList.add("is-active")}),e.addEventListener("mouseleave",()=>{t.classList.remove("is-active")}))})})